14707   R.buildTree(Chain);
14708   if (R.isTreeTinyAndNotFullyVectorizable())
14709     return false;
14710   if (R.isLoadCombineCandidate())
14711     return false;
14712   R.reorderTopToBottom();
14713   R.reorderBottomToTop();
14714   R.buildExternalUses();
14715 
14716   R.computeMinimumValueSizes();
