14722     LLVM_DEBUG(dbgs() << "SLP: Decided to vectorize cost = " << Cost << "\n");
14723 
14724     using namespace ore;
14725 
14726     R.getORE()->emit(OptimizationRemark(SV_NAME, "StoresVectorized",
14727                                         cast<StoreInst>(Chain[0]))
14728                      << "Stores SLP vectorized with cost " << NV("Cost", Cost)
14729                      << " and with tree size "
14730                      << NV("TreeSize", R.getTreeSize()));
14731 
14732     R.vectorizeTree();
14733     return true;
14734   }
14735 
14736   return false;
14737 }
